DetectionRule.DetectionLogic:
let SuspiciousRemoteTools = dynamic([ "psexec", "psexec64", "psexesvc", "PSEXESVC.exe", "wmic", "WMIC.exe", "wsmprovhost", "winrshost", "mstsc", "msrdc", "schtasks", "at.exe", "sc.exe", "net.exe", "powershell", "pwsh" ]);
let SuspiciousServices = dynamic([ "PSEXESVC", "RemComSvc", "WmiApSrv", "TrustedInstaller" ]);
// Detect service creation from suspicious remote tools DeviceProcessEvents | where Timestamp > ago(4h) | where FileName in~ (SuspiciousRemoteTools) and (ProcessCommandLine has "service" or ProcessCommandLine has "sc" or ProcessCommandLine has "net") | extend ActionType = case( ProcessCommandLine has_any ("create", "config", "failure"), "ServiceManipulation", ProcessCommandLine has_any ("start", "stop", "pause"), "ServiceControl", "Other" ) | where ActionType != "Other" | summarize ServiceActions = count(), Commands = makeset(ProcessCommandLine) by DeviceId, FileName, InitiatingProcessFileName, InitiatingProcessCommandLine, TargetDevice = tostring(split(ProcessCommandLine, '\\\\')[-1]) | where ServiceActions >= 2
// Also detect SMB connections followed by suspicious execution union ( DeviceNetworkEvents | where Timestamp > ago(4h) | where Protocol == "SMB" or RemotePort == 445 or RemotePort == 139 | where ActionType in~ ("ConnectionAccepted", "ConnectionInitiated") | summarize SMBConnections = dcount(RemoteDeviceName) by DeviceId, InitiatingProcessFileName, InitiatingProcessCommandLine | where SMBConnections >= 5 | join kind=inner ( DeviceProcessEvents | where Timestamp > ago(4h) | where FileName in~ (SuspiciousRemoteTools) ) on DeviceId | where FileName !~ InitiatingProcessFileName | extend RiskScore = case( InitiatingProcessFileName in~ ("psexec", "psexec64"), 95, InitiatingProcessFileName == "wmic", 90, FileName == "powershell" and SMBConnections >= 10, 88, true, 80 ) | where RiskScore >= 80 | project DeviceId, InitiatingProcessFileName, FileName, SMBConnections, RiskScore ) | extend FinalRiskScore = case( RiskScore >= 90, "High", RiskScore >= 80, "Medium", "Low" ) | project-reorder Timestamp, DeviceId, InitiatingProcessFileName, FinalRiskScore, SMBConnections

let SuspiciousWMIClasses = dynamic([ "Win32_Process", "Win32_Service", "Win32_Product", "Win32_StartupCommand", "Win32_ComputerSystem", "Win32_OperatingSystem", "Win32_LoggedOnUser", "Win32_LogicalDisk", "Win32_NetworkAdapterConfiguration" ]);
let SuspiciousWMIQueries = @" SELECT * FROM Win32_Process WHERE Name LIKE '%powershell%' SELECT * FROM Win32_Process WHERE Name LIKE '%cmd%' SELECT * FROM Win32_Service WHERE State = 'Running' SELECT * FROM Win32_ComputerSystem SELECT * FROM Win32_OperatingSystem SELECT * FROM Win32_StartupCommand ASSOCIATORS OF {Win32_Process} ";
// Detect WMI process creation from unusual parents DeviceProcessEvents | where Timestamp > ago(6h) | where FileName == "wmiprvse.exe" and InitiatingProcessFileName !in~ ("services.exe", "svchost.exe", "wmiapsrv.exe") | extend ParentProcess = InitiatingProcessFileName | extend ChildProcess = tostring(split(ProcessCommandLine, ' ')[0]) | where ChildProcess in~ ("cmd.exe", "powershell.exe", "wscript.exe", "cscript.exe", "rundll32.exe") or ProcessCommandLine has_any (SuspiciousWMIClasses) | summarize WMIExecutions = count(), Commands = makeset(ProcessCommandLine) by DeviceId, ParentProcess, ChildProcess, AccountName | where WMIExecutions >= 3
// Also detect remote WMI connections (DCOM) union ( DeviceNetworkEvents | where Timestamp > ago(6h) | where Protocol == "DCERPC" or RemotePort == 135 | where InitiatingProcessFileName == "wmiprvse.exe" | where ActionType == "ConnectionInitiated" | extend TargetIP = RemoteIP, TargetPort = RemotePort | summarize RemoteConnections = dcount(TargetIP) by DeviceId, InitiatingProcessFileName | where RemoteConnections >= 10 | join kind=inner ( DeviceProcessEvents | where Timestamp > ago(6h) | where FileName == "wmiprvse.exe" and InitiatingProcessFileName !in~ ("services.exe", "svchost.exe") ) on DeviceId | extend RiskScore = case( RemoteConnections >= 20, 92, RemoteConnections >= 10, 88, true, 80 ) ) | extend FinalRisk = case( WMIExecutions >= 10 or RemoteConnections >= 20, "High", WMIExecutions >= 5 or RemoteConnections >= 10, "Medium", "Low" ) | project-reorder Timestamp, DeviceId, FinalRisk, WMIExecutions, RemoteConnections

let ServiceCreationCommands = dynamic([ "sc.exe create", "sc create", "sc\\.exe create", "New-Service", "InstallUtil", "installutil.exe" ]);
let SuspiciousServiceNames = dynamic([ "PSEXESVC", "RemComSvc", "WmiApSrv", "TrustedInstaller", "Spooler", "EventLog", "SamSs", "Lsa", "WinDefend" ]);
// Detect remote service creation commands DeviceProcessEvents | where Timestamp > ago(4h) | where (FileName in~ ("sc.exe", "powershell.exe", "pwsh.exe", "cmd.exe") and ProcessCommandLine has_any (ServiceCreationCommands)) or (ProcessCommandLine contains "\\\\" and ProcessCommandLine contains "service") | extend TargetDevice = extract(@"\\\\([^\\\\]+)", 1, ProcessCommandLine) | extend ServiceName = extract(@"create\\s+([^ ]+)", 1, ProcessCommandLine, typeof(string)) | where isnotempty(TargetDevice) or ServiceName in~ (SuspiciousServiceNames) | summarize ServiceCreations = count(), UniqueServices = dcount(ServiceName), Commands = makeset(ProcessCommandLine) by DeviceId, InitiatingProcessFileName, TargetDevice, AccountName | where ServiceCreations >= 2 or UniqueServices >= 2
// Also detect service modifications that enable remote access union ( DeviceRegistryEvents | where Timestamp > ago(4h) | where RegistryKey has "SYSTEM\\CurrentControlSet\\Services" and RegistryKey endswith "ImagePath" and RegistryValue contains "\\\\" | extend ServicePath = RegistryValue | where ServicePath matches regex @"\\\\[^\\\\]+\\\\[^\\\\\\]+\\[^\\\\]+" | summarize ServiceModifications = count() by DeviceId, RegistryKey, ServicePath | where ServiceModifications >= 1 ) | extend RiskScore = case( ServiceCreations >= 5 or UniqueServices >= 3, 94, ServiceCreations >= 3 or UniqueServices >= 2, 88, TargetDevice !in~ ("127.0.0.1", "localhost"), 90, true, 70 ) | where RiskScore >= 88 | project-reorder Timestamp, DeviceId, RiskScore, ServiceCreations, TargetDevice

// This detection requires monitoring of NTLM authentication events // and correlation of NTLM hashes across multiple logon attempts
SecurityEvent | where TimeGenerated > ago(2h) | where EventID == 4624 // Successful Logon and LogonType in~ (3, 8, 10) // Network, NetworkClearText, RemoteInteractive | where AuthenticationPackageName == "NTLM" | extend WorkstationName = tostring(split(WorkstationName, '.')[0]) | summarize LogonCount = count(), UniqueSources = dcount(WorkstationName), TargetSystems = makeset(TargetSystemName) by AccountName, NTLMHash = SubjectUserName, IpAddress | where UniqueSources >= 3 // Same hash from 3+ different source machines and LogonCount >= 5 // Multiple authentication attempts
// Also monitor for failed NTLM authentications with same hash union ( SecurityEvent | where TimeGenerated > ago(2h) | where EventID == 4625 // Failed Logon and LogonType in~ (3, 8, 10) | where AuthenticationPackageName == "NTLM" | summarize FailedAttempts = count(), UniqueSources = dcount(WorkstationName) by AccountName, NTLMHash = SubjectUserName | where UniqueSources >= 3 and FailedAttempts >= 10 ) | extend PassTheHashConfidence = case( UniqueSources >= 5 and LogonCount >= 10, "Critical", UniqueSources >= 3 and LogonCount >= 5, "High", "Medium" ) | where PassTheHashConfidence in~ ("Critical", "High") | project-reorder TimeGenerated, AccountName, UniqueSources, LogonCount, PassTheHashConfidence
